class Piece:
    def __init__(self, color):
        self.color = color

    def is_king(self):
        return False


class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['r', 'b']
        row_step = 1
        for i, color in enumerate(colors * 4):
            start_row = (i % 2) * row_step
            for j in range(start_row, 8, 2):
                self.board[i][j] = Piece(color)

    def move_piece(self, from_pos, to_pos):
        piece = self.board[from_pos[0]][from_pos[1]]
        self.board[from_pos[0]][from_pos[1]] = None
        self.board[to_pos[0]][to_pos[1]] = piece

    def get_piece(self, pos):
        return self.board[pos[0]][pos[1]]

    def is_valid_move(self, from_pos, to_pos):
        # Implement move validation logic here
        pass


class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def switch_player(self):
        self.current_player = 'b' if self.current_player == 'r' else 'r'

    def play_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos)
        if piece is not None and piece.color == self.current_player:
            if self.board.is_valid_move(from_pos, to_pos):
                self.board.move_piece(from_pos, to_pos)
